// ❌ Throws ElementNotInteractableException if the button is still fading in
driver.findElement(By.id("submit")).click();

// ✅ Wait for the element to be visible and interactable
WebDriverWait wait = new WebDriverWait(driver, Duration.ofSeconds(10));
WebElement submitBtn = wait.until(ExpectedConditions.elementToBeClickable(By.id("submit")));
submitBtn.click();

// ⚠️ Workaround: Force click using JavaScript (bypasses UI visibility checks)
JavascriptExecutor js = (JavascriptExecutor) driver;
js.executeScript("arguments[0].click();", driver.findElement(By.id("submit")));
